function adjustSpacing(){const t=document.getElementById("reference-displacement-1"),e=document.getElementById("reference-displacement-2");if(!t||!e)return;e.style.marginTop="";const s=t.getBoundingClientRect().bottom+window.scrollY,o=e.getBoundingClientRect().top+window.scrollY,n=o-s;n<60&&(e.style.marginTop=60-n+"px")}window.addEventListener("resize",adjustSpacing),document.addEventListener("DOMContentLoaded",adjustSpacing)